/** 计算SOON因子命中 */
function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
  const factors = [];
  const t = TODAY_DATE;

  function check(baselineKey, rhythmArr, factorName, opts = {}) {
    const bDate = parseDate(bl[baselineKey]);
    if (!bDate) return;
    const days = daysBetween(bDate, t);
    if (days < 1) return; // 今天刚设基线，不触发

    const hitIdx = rhythmHit(days, rhythmArr);
    if (hitIdx >= 0) {
      const cumulative = rhythmArr.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
      factors.push({
        factor: factorName,
        days,
        rhythmDay: cumulative,
        intervalIndex: hitIdx,
        baseline: bl[baselineKey],
        ...opts,
      });
    }
  }

  switch (stage) {
    case '需求探索':
      check('S1', RHYTHM.S1, 'S1 该深挖需求了');
      break;
    case '报价已发':
      check('S2', RHYTHM.S2, 'S2 该追问了');
      break;
    case '谈判中':
      check('S3', RHYTHM.S3, 'S3 该推进了');
      break;
    case '待付款':
      check('S4', RHYTHM.S4, 'S4 该催款了');
      // 超过Day7后每7天观察
      if (bl.S4) {
        const days = daysBetween(parseDate(bl.S4), t);
        if (days > 7 && days % 7 === 0) {
          factors.push({ factor: 'S4 该催款了(观察)', days, baseline: bl.S4, observeMode: true });
        }
      }
      break;
    case '待发货':
      // S5a: 双基线
      if (bl.S5a_A) {
        const daysA = daysBetween(parseDate(bl.S5a_A), t);
        const interval = s5aInterval(meta);
        if (daysA >= interval && daysA % interval === 0) {
          factors.push({ factor: 'S5a 该更新进度了', days: daysA, interval, baseline: bl.S5a_A, priority: 'normal' });
        }
      }
      if (meta.committed_ship_date) {
        const shipDate = parseDate(meta.committed_ship_date);
        if (shipDate && t > shipDate) {
          const overdue = daysBetween(shipDate, t);
          factors.push({ factor: 'S5a 该更新进度了(超期)', days: overdue, priority: 'high', reason: '超承诺发货日' });
        }
      }
      // S5b: 该要地址了
      if (!meta.has_address && bl.S5b) {
        const days = daysBetween(parseDate(bl.S5b), t);
        if (days >= 1) {
          factors.push({ factor: 'S5b 该要地址了', days, baseline: bl.S5b });
        }
      }
      break;
    case '已发货/在途':
      check('S6', [s6Interval(meta)], 'S6 该更新物流了', { interval: s6Interval(meta) });
      break;
    case '已签收':
      check('S7a', RHYTHM.S7a, 'S7a 该回访了');
      if (bl.S7b) {
        const rhythm = meta.customer_type === '样品单' ? RHYTHM.S7b_sample : RHYTHM.S7b_bulk;
        check('S7b', rhythm, 'S7b 该推返单了');
      }
      break;
    case '售后':
      check('S8', RHYTHM.S8, 'S8 该收尾了');
      break;
    case '待返单':
      if (bl.S9) {
        const rhythm = meta.customer_type === '样品单' ? RHYTHM.S9_sample : RHYTHM.S9_bulk;
        check('S9', rhythm, 'S9 该接触了');
      }
      break;
  }

  return factors;
}

/** 因子命中统计 */
function summarizeFactors(soonCustomers) {
  const factorCounts = {};
  for (const c of soonCustomers) {
    for (const f of c.factors) {
      const key = f.factor.split('(')[0].trim();
      factorCounts[key] = (factorCounts[key] || 0) + 1;
    }
  }
  return factorCounts;
}

/** 生成 markdown 报告 */
function generateReport(newStageCounts, soonOutput, coldOutput, corrections) {
  const lines = [
    `# OKKI SOON 层初始化报告`,
    `> 日期: ${TODAY}`,
