    // 统计
    stageStats[oldStage] = (stageStats[oldStage] || 0) + 1;
    if (oldStage !== newStage && newStage !== null) {
      stageCorrections.push({ cid: c.cid, name: c.name, oldStage, newStage });
    }

    const tier = getTier(c.name, c.country);
    const lastMsgDate = parseDate(c.lastMsgTime);
    const daysSinceMsg = lastMsgDate ? daysBetween(lastMsgDate, TODAY_DATE) : 999;
    const lastSenderIsMe = c.lastSender === '我';

    // 初始化 meta
    const meta = {
      transit_days: null,
      customer_tier: tier,
      committed_ship_date: null,
      has_address: null,
      customer_type: (oldStage === '样品阶段') ? '样品单' : '大货',
      repurchase_cycle_days: null,
      target_market: isAfricaOrMiddleEast(c.country) ? 'africa_me' : 'other',
      s8_boundary_checked: false,
    };

    // 初始化 baselines (全部 null)
    const bl = { S1: null, S2: null, S3: null, S4: null, S5a_A: null, S5a_B: null, S5b: null, S6: null, S7a: null, S7b: null, S8: null, S9: null };

    const stageUpdated = null;

    if (newStage) {
      // 根据阶段设置对应基线
      switch (newStage) {
        case '需求探索':
          if (lastSenderIsMe) bl.S1 = c.lastMsgTime;
          break;
        case '报价已发':
          bl.S2 = c.lastMsgTime;
          break;
        case '谈判中':
          bl.S3 = c.lastMsgTime;
          break;
        case '待付款':
          bl.S4 = c.lastMsgTime;
