// ============ 配置 ============

/** 旧阶段 → 新9阶段映射 */
const STAGE_MAP = {
  '需求探索': '需求探索',
  '报价已发': '报价已发',
  '谈判中': '谈判中',
  '待付款': '待付款',
  '待发货': '待发货',
  '已发货/在途': '已发货/在途',
