          stage: newStage,
          heat: c.heat,
          tier,
          daysSinceLastContact: c.daysSinceLastContact,
          factors,
        });
      }
    } else {
      // 未知阶段 → 冷层
      baselines[c.cid] = {
        name: c.name,
        country: c.country,
        stage: null,
        stage_updated: null,
        baselines: bl,
        meta,
        _heat: c.heat,
        _daysSinceLastContact: c.daysSinceLastContact,
      };
      coldCustomers.push({
        cid: c.cid,
        name: c.name,
        country: c.country,
        daysSinceLastContact: c.daysSinceLastContact,
        tier,
        lastMsgTime: c.lastMsgTime,
        lastSender: c.lastSender,
      });
