const fs = require('fs');
const path = require('path');

const TODAY = '2026-05-18';
const TODAY_DATE = new Date(TODAY);

// ============ 配置 ============

/** 旧阶段 → 新9阶段映射 */
const STAGE_MAP = {
  '需求探索': '需求探索',
  '报价已发': '报价已发',
  '谈判中': '谈判中',
  '待付款': '待付款',
