      // S5a-B: 承诺发货日超期检查（需外部填写 committed_ship_date）
      if (meta.committed_ship_date && bl.S5a_A) {
        const shipDate = parseDate(meta.committed_ship_date);
        if (shipDate && t > shipDate) {
          const overdue = daysBetween(shipDate, t);
          factors.push({ factor: 'S5a 该更新进度了(超期)', days: overdue, priority: 'high', reason: '超承诺发货日' });
        }
      }
      // S5b: 地址催要（三态）
      if (bl.S5b) {
        const days = daysBetween(parseDate(bl.S5b), t);
        if (meta.has_address === false && days >= 1) {
          factors.push({ factor: 'S5b 该要地址了', days, baseline: bl.S5b, priority: 'normal' });
        } else if (meta.has_address === null && days > 30) {
          factors.push({ factor: 'S5b 该确认地址状态了', days, baseline: bl.S5b, priority: 'low', note: '未知是否有地址，请人工确认' });
