1	/**
2	 * 任务1-4: factor_baselines.json 初始化 + 阶段标签修正 + SOON层建卡 + 冷层/冷冻分层
3	 *
4	 * 输入: heat_classification.json (466人)
5	 * 输出: factor_baselines.json, SOON清单, 冷层/冷冻层清单
6	 */
7	
8	const fs = require('fs');
9	const path = require('path');
10	
11	const TODAY = '2026-05-18';
12	const TODAY_DATE = new Date(TODAY);
13	
14	// ============ 配置 ============
15	
16	/** 旧阶段 → 新9阶段映射 */
17	const STAGE_MAP = {
18	  '需求探索': '需求探索',
19	  '报价已发': '报价已发',
20	  '谈判中': '谈判中',
21	  '待付款': '待付款',
22	  '待发货': '待发货',
23	  '已发货/在途': '已发货/在途',
24	  '已签收': '已签收',
25	  '售后': '售后',
26	  '待返单': '待返单',
27	  // 旧标签映射
28	  '初询沟通': '需求探索',
29	  'PI已发': '报价已发',
30	  '谈判/样品': '谈判中',
31	  '样品阶段': '谈判中',  // 保守: 未付款→谈判中
32	  // 未知保持null→冷层
33	  '未知': null,
34	};
35	
36	/** SOON因子节奏表 (V5) */
37	const RHYTHM = {
38	  S1:  [1, 2, 3, 5, 7, 9, 15, 30],  // 需求探索 该深挖需求了
39	  S2:  [1, 3, 5, 15, 30],            // 报价已发 该追问了
40	  S3:  [1, 3, 5, 7, 15, 30],         // 谈判中 该推进了
41	  S4:  [1, 3, 5, 7],                  // 待付款 该催款了 (+每7天观察)
42	  S8:  [1, 2, 3, 5, 7, 15, 30],      // 售后 该收尾了
43	  S7a: [3, 15, 15, 30, 30, 60],       // 已签收 该回访了 (累计)
44	  S7b_sample: [7],                     // 样品单 该推返单
45	  S7b_bulk: [30],                      // 大货 该推返单
46	  S9_sample: [3, 7, 7, 15, 15, 30, 30],
47	  S9_bulk:   [7, 15, 15, 30, 30, 60, 60],
48	};
49	RHYTHM.S1_MAX = 72;   // 1+2+3+5+7+9+15+30
50	RHYTHM.S4_MAX = 16;   // 1+3+5+7
51	
52	/** S5a 双基线间隔计算 */
53	function s5aInterval(meta) {
54	  if (meta.customer_type === '样品单') return 3;
55	  if (!meta.transit_days) return 7; // 默认大货交期35天÷5≈7
56	  const interval = Math.round(meta.transit_days / 5);
57	  return Math.max(3, Math.min(10, interval));
58	}
59	
60	/** S6 间隔: 时效÷N */
61	function s6Interval(meta) {
62	  const transitDays = meta.transit_days || 25;
63	  const N = { S: 6, A: 6, B: 5, C: 5, D: 4 }[meta.customer_tier] || 5;
64	  const interval = Math.round(transitDays / N);
65	  return Math.max(2, Math.min(15, interval));
66	}
67	
68	// ============ 辅助函数 ============
69	
70	function parseDate(str) {
71	  if (!str) return null;
72	  const d = new Date(str);
73	  return isNaN(d.getTime()) ? null : d;
74	}
75	
76	function daysBetween(d1, d2) {
77	  return Math.floor((d2.getTime() - d1.getTime()) / (1000 * 60 * 60 * 24));
78	}
79	
80	/** 判定节奏命中：返回命中的天数索引，未命中返回-1 */
81	function rhythmHit(days, rhythmArr) {
82	  // 找到 days 落在哪个间隔的 ±0 容差内 (当天命中)
83	  for (let i = 0; i < rhythmArr.length; i++) {
84	    const cumulative = rhythmArr.slice(0, i + 1).reduce((a, b) => a + b, 0);
85	    if (days === cumulative) return i;
86	  }
87	  return -1;
88	}
89	
90	/** 获取客户等级 (从 dashboard_snapshot 交叉匹配或默认) */
91	let tierMap = null;
92	function loadTierMap() {
93	  if (tierMap) return tierMap;
94	  tierMap = new Map();
95	  try {
96	    const snap = JSON.parse(fs.readFileSync(
97	      path.join(__dirname, '..', 'output', '.dashboard_snapshot.json'), 'utf-8'
98	    ));
99	    for (const c of snap.customers || []) {
100	      const key = (c.name || '').toLowerCase() + '|' + (c.country || '');
101	      tierMap.set(key, c.quality || 'C');
102	    }
103	  } catch (e) { /* ignore */ }
104	  return tierMap;
105	}
106	
107	function getTierWithSource(name, country) {
108	  const map = loadTierMap();
109	  const key = (name || '').toLowerCase().trim() + '|' + (country || '').toUpperCase().trim();
110	  const matched = map.get(key);
111	  if (matched) return { tier: matched, source: 'dashboard_snapshot' };
112	  return { tier: 'C', source: 'default_C' };
113	}
114	
115	/** 判定 target_market 是否非洲/中东 */
116	function isAfricaOrMiddleEast(country) {
117	  const africaME = ['SD','EG','CD','ZM','CI','SA','AE','IQ','GH','NG','KE','TZ','UG','ET','CM','SN','ML','BF','BJ','TG','LY','MA','DZ','TN','KW','QA','BH','OM','JO','LB','YE','SY','PS','CG','GA','MR','SO'];
118	  return africaME.includes((country || '').toUpperCase());
119	}
120	
121	// ============ 主流程 ============
122	
123	function main() {
124	  // 读取源数据
125	  const srcPath = path.join(__dirname, '..', 'data', 'heat_classification.json');
126	  const data = JSON.parse(fs.readFileSync(srcPath, 'utf-8'));
127	  const customers = data.results;
128	  console.log(`读取 ${customers.length} 条客户记录`);
129	
130	  const baselines = {};
131	  const stageStats = {};       // 新阶段统计
132	  const stageCorrections = []; // 阶段修正记录
133	  const soonCustomers = [];    // SOON层清单
134	  const coldCustomers = [];    // 冷层清单
135	  const frozenLayers = {       // 冷冻层分层
136	    highValue: [],   // 高价值沉睡 (S/A/B级)
137	    deepFrozen: [],  // 深度冷冻 (C级>180天)
138	    normal: [],      // 普通沉睡
139	    neverDeal: [],   // 从未成交 (D级)
140	  };
141	
142	  for (const c of customers) {
143	    const oldStage = c.stage;
144	    const newStage = STAGE_MAP[oldStage];
145	
146	    // 统计
147	    stageStats[oldStage] = (stageStats[oldStage] || 0) + 1;
148	    if (oldStage !== newStage && newStage !== null) {
149	      stageCorrections.push({ cid: c.cid, name: c.name, oldStage, newStage });
150	    }
151	
152	    const tierInfo = getTierWithSource(c.name, c.country);
153	    const tier = tierInfo.tier;
154	    const lastMsgDate = parseDate(c.lastMsgTime);
155	    const daysSinceMsg = lastMsgDate ? daysBetween(lastMsgDate, TODAY_DATE) : 999;
156	    const lastSenderIsMe = c.lastSender === '我';
157	
158	    // 初始化 meta
159	    const meta = {
160	      transit_days: null,
161	      customer_tier: tier,
162	      _tier_source: tierInfo.source,
163	      committed_ship_date: null,
164	      has_address: null,
165	      customer_type: (oldStage === '样品阶段') ? '样品单' : '大货',
166	      repurchase_cycle_days: null,
167	      target_market: isAfricaOrMiddleEast(c.country) ? 'africa_me' : 'other',
168	      s8_boundary_checked: false,
169	    };
170	
171	    // 初始化 baselines (全部 null)
172	    const bl = { S1: null, S2: null, S3: null, S4: null, S5a_A: null, S5a_B: null, S5b: null, S6: null, S7a: null, S7b: null, S8: null, S9: null };
173	
174	    const stageUpdated = null;
175	
176	    if (newStage) {
177	      // 根据阶段设置对应基线
178	      switch (newStage) {
179	        case '需求探索':
180	          if (lastSenderIsMe) bl.S1 = c.lastMsgTime;
181	          break;
182	        case '报价已发':
183	          bl.S2 = c.lastMsgTime;
184	          break;
185	        case '谈判中':
186	          bl.S3 = c.lastMsgTime;
187	          break;
188	        case '待付款':
189	          bl.S4 = c.lastMsgTime;
190	          break;
191	        case '待发货':
192	          if (lastSenderIsMe) bl.S5a_A = c.lastMsgTime;
193	          bl.S5b = c.lastMsgTime; // proxy for 付款到账日
194	          break;
195	        case '已发货/在途':
196	          bl.S6 = c.lastMsgTime;
197	          meta.transit_days = isAfricaOrMiddleEast(c.country) ? 30 : 25;
198	          break;
199	        case '已签收':
200	          bl.S7a = c.lastMsgTime;
201	          bl.S7b = c.lastMsgTime;
202	          break;
203	        case '售后':
204	          if (lastSenderIsMe) bl.S8 = c.lastMsgTime;
205	          break;
206	        case '待返单':
207	          bl.S9 = c.lastMsgTime;
208	          break;
209	      }
210	
211	      // 计算 SOON 因子命中
212	      const factors = computeFactors(newStage, bl, meta, daysSinceMsg, lastSenderIsMe);
213	
214	      baselines[c.cid] = {
215	        name: c.name,
216	        country: c.country,
217	        stage: newStage,
218	        stage_updated: stageUpdated,
219	        baselines: bl,
220	        meta,
221	        _heat: c.heat,
222	        _daysSinceLastContact: c.daysSinceLastContact,
223	      };
224	
225	      if (factors.length > 0) {
226	        soonCustomers.push({
227	          cid: c.cid,
228	          name: c.name,
229	          country: c.country,
230	          stage: newStage,
231	          heat: c.heat,
232	          tier,
233	          daysSinceLastContact: c.daysSinceLastContact,
234	          factors,
235	        });
236	      }
237	    } else {
238	      // 未知阶段 → 冷层
239	      baselines[c.cid] = {
240	        name: c.name,
241	        country: c.country,
242	        stage: null,
243	        stage_updated: null,
244	        baselines: bl,
245	        meta,
246	        _heat: c.heat,
247	        _daysSinceLastContact: c.daysSinceLastContact,
248	      };
249	      coldCustomers.push({
250	        cid: c.cid,
251	        name: c.name,
252	        country: c.country,
253	        daysSinceLastContact: c.daysSinceLastContact,
254	        tier,
255	        lastMsgTime: c.lastMsgTime,
256	        lastSender: c.lastSender,
257	      });
258	    }
