271	    }
272	  }
273	
274	  // ==== 输出统计 ====
275	  console.log('\n===== 阶段映射统计 =====');
276	  for (const [k, v] of Object.entries(stageStats).sort((a, b) => b[1] - a[1])) {
277	    const mapped = STAGE_MAP[k];
278	    const arrow = mapped === k ? '→ 不变' : mapped === null ? '→ 冷层' : `→ ${mapped}`;
279	    console.log(`  ${k}: ${v} ${arrow}`);
