289	    console.log(`  ${k}: ${v}`);
290	  }
291	
292	  console.log(`\n===== SOON层: ${soonCustomers.length}人 =====`);
293	  console.log(`===== 冷层: ${coldCustomers.length}人 =====`);
294	  console.log(`  高价值沉睡 (S/A/B级): ${frozenLayers.highValue.length}`);
295	  console.log(`  深度冷冻 (C级>180天): ${frozenLayers.deepFrozen.length}`);
