366	/** 计算SOON因子命中 */
367	function computeFactors(stage, bl, meta, daysSinceMsg, lastSenderIsMe) {
368	  const factors = [];
369	  const t = TODAY_DATE;
370	
371	  switch (stage) {
372	    case '需求探索': {
373	      const d = parseDate(bl.S1);
374	      if (!d) break;
375	      const days = daysBetween(d, t);
