378	      if (hitIdx >= 0) {
379	        const cumulative = RHYTHM.S1.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
380	        factors.push({ factor: 'S1 该深挖需求了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S1 });
381	      } else if (days <= 45) {
382	        const lastInterval = RHYTHM.S1[RHYTHM.S1.length - 1];
383	        if ((days - RHYTHM.S1_MAX) % lastInterval === 0) {
384	          factors.push({ factor: 'S1 该深挖需求了(兜底)', days, baseline: bl.S1 });
385	        }
386	      }
387	      break;
388	    }
389	    case '报价已发': {
390	      const d = parseDate(bl.S2);
391	      if (!d) break;
392	      const days = daysBetween(d, t);
393	      if (days < 1) break;
394	      const hitIdx = rhythmHit(days, RHYTHM.S2);
395	      if (hitIdx >= 0) {
396	        const cumulative = RHYTHM.S2.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
397	        factors.push({ factor: 'S2 该追问了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S2 });
398	      }
