400	    }
401	    case '谈判中': {
402	      const d = parseDate(bl.S3);
403	      if (!d) break;
404	      const days = daysBetween(d, t);
405	      if (days < 1) break;
406	      const hitIdx = rhythmHit(days, RHYTHM.S3);
