489	              factors.push({ factor: 'S7b 该推返单了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S7b });
490	            }
491	          }
492	        }
493	      }
494	      break;
495	    }
496	    case '售后': {
497	      const d = parseDate(bl.S8);
498	      if (!d) break;
499	      const days = daysBetween(d, t);
500	      if (days < 1) break;
501	      const hitIdx = rhythmHit(days, RHYTHM.S8);
502	      if (hitIdx >= 0) {
503	        const cumulative = RHYTHM.S8.slice(0, hitIdx + 1).reduce((a, b) => a + b, 0);
504	        factors.push({ factor: 'S8 该收尾了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S8 });
505	      }
506	      break;
507	    }
508	    case '待返单': {
509	      if (bl.S9) {
510	        const d = parseDate(bl.S9);
