518	              factors.push({ factor: 'S9 该接触了', days, rhythmDay: cumulative, intervalIndex: hitIdx, baseline: bl.S9 });
519	            }
520	          }
521	        }
522	      }
523	      break;
524	    }
525	  }
526	
527	  return factors;
528	}
