  '平台规则提醒', '为了更好的保护买卖双方利益', '维护平台有序的市场秩序', '引导买家站外沟通',
];

function computePreComputed(convList) {
  const now = Date.now();
  const chatDir = path.join(DATA_DIR, 'chat_history');

  for (const c of convList) {
    c.preComputed = {};

    // 1. 是否未读
    c.preComputed.isUnread = (c.unreadCount || 0) > 0;

    // 2. 距上次联系天数
    const lct = c.lastContactTimeLong || c.lastContactTime || 0;
    c.preComputed.daysSinceLastContact = lct > 0 ? Math.floor((now - lct) / 86400000) : null;

    // 3. latestMessage 是否是系统消息
    const lmContent = c.latestMessage?.content || '';
    c.preComputed.isLatestMessageSystem = false;
    if (lmContent) {
      for (const pat of SYSTEM_MSG_PATTERNS) {
        if (lmContent.includes(pat)) {
          c.preComputed.isLatestMessageSystem = true;
          break;
        }
      }
    }

    // 4. 是否有 chat_history 文件
    const fileName = sanitizeFilename(c.cid) + '.json';
    const filePath = path.join(chatDir, fileName);
    c.preComputed.hasChatHistoryFile = fs.existsSync(filePath);

    // 5. 是否有真实消息（chat_history 文件中存在非系统消息）
    c.preComputed.hasRealMessages = false;
    if (c.preComputed.hasChatHistoryFile) {
      try {
        const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
        for (const msg of (data.messages || [])) {
          const content = msg.message?.content?.text?.content || '';
          if (!content) continue;
          let isSys = false;
          for (const pat of SYSTEM_MSG_PATTERNS) {
            if (content.includes(pat)) { isSys = true; break; }
          }
          if (!isSys) {
            c.preComputed.hasRealMessages = true;
            break;
          }
        }
      } catch (e) {}
    }
  }

  // 重新保存带 preComputed 的元数据
  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
  const latestMeta = {
    exportedAt: new Date().toISOString(),
    total: convList.length,
    conversations: convList,
  };
  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
  log(`preComputed 已计算，元数据已更新`);
}

function printSummary(convData, changed) {
  // 统计（基于原始消息数据，不依赖 latestMessage）
  const now = Date.now();
  const last24h = convData.filter(c => (c.lastContactTime || 0) > now - 86400000).length;

  // 从 chat_history 文件统计客户回复（不是从 latestMessage）
  let totalCustomerMsgs = 0;
  let totalOurMsgs = 0;
  let customersReplied = new Set();
  const CUTOFF = now - 7 * 86400000;

  const chatDir = path.join(DATA_DIR, 'chat_history');
  if (fs.existsSync(chatDir)) {
    const files = fs.readdirSync(chatDir).filter(f => f.endsWith('.json') && f !== '_summary.json');
    for (const file of files) {
      try {
        const data = JSON.parse(fs.readFileSync(path.join(chatDir, file), 'utf-8'));
        for (const msg of (data.messages || [])) {
          const ts = msg.message?.createAt || 0;
          if (ts < CUTOFF) continue;
          const sender = msg.message?.sender?.uid || '';
          const content = msg.message?.content?.text?.content || '';
          if (!content) continue;
          if (sender === '2500000853693@icbu') {
            totalOurMsgs++;
          } else {
            totalCustomerMsgs++;
            customersReplied.add(data.cid || file);
          }
        }
      } catch (e) {}
    }
  }

  log('');
  log('========== 同步摘要 ==========');
  log(`总会话: ${convData.length}`);
  log(`变化会话: ${changed.length}`);
  log(`24h内有 activity: ${last24h}`);
  log('');
  log(`近7天消息 (来自 chat_history 实测):`);
  log(`  客户回复: ${totalCustomerMsgs} 条 / ${customersReplied.size} 人`);
  log(`  我方发送: ${totalOurMsgs} 条`);
  log(`数据已保存到 data/ 目录`);
  log('==============================');
}

// ===================== 启动 =====================

main().catch(err => {
  log(`致命错误: ${err.message}`);
  console.error(err);
  process.exit(1);
});
