#!/usr/bin/env node
/**
 * batch_classify_heat.js — 批量初筛 NOW/SOON/COLD
 *
 * 读取所有聊天文件，根据最后几条消息自动判定热度：
 *   NOW  — 客户最后发消息，等待我方回复
 *   SOON — 我方最后发消息，等待客户回复
 *   COLD — 超过 90 天无互动
 *
 * 输出: 分类结果 JSON + 摘要统计
 */

const fs = require("fs");
const path = require("path");

const DATA_DIR = path.resolve(__dirname, "..", "data");
const CHAT_DIR = path.join(DATA_DIR, "chat_history");
const LATEST_PATH = path.join(DATA_DIR, "tm_conversations_latest.json");
const OUT_PATH = path.join(DATA_DIR, "heat_classification.json");

const NOW_WINDOW_DAYS = 90; // 90天内活跃才考虑 NOW/SOON
const CHECK_MSG_COUNT = 10; // 读取最后 N 条消息判断
const OUR_UID_MARKER = "2500000853693";

// ── 读取会话索引 ──────────────────────────────────────────
const latest = JSON.parse(fs.readFileSync(LATEST_PATH, "utf-8"));
const conversations = latest.conversations || [];

function isSystemMessage(msg) {
  try {
    const ext = msg.message?.extension;
    if (ext?.systemMessage === true) return true;
    const bmi = ext?.basicMessageInfo;
    if (typeof bmi === "string" && bmi.includes('"systemMessage":true')) return true;
    return false;
  } catch {
    return false;
  }
}

function getMsgText(msg) {
  try { return msg.message?.content?.text?.content || ""; } catch { return ""; }
}

function getMsgTime(msg) {
  try { return msg.message?.createAt || 0; } catch { return 0; }
}

function getSenderIsUs(msg) {
  try { return (msg.message?.sender?.uid || "").includes(OUR_UID_MARKER); } catch { return false; }

