  // COLD: >90 days
  if (daysSinceLastContact > NOW_WINDOW_DAYS) {
    results.push({
      cid: conv.cid,
      name: conv.name,
      country: conv.complianceCountryCode || "?",
      daysSinceLastContact,
      heat: "COLD",
      stage: "未知",
      lastSender: null,
      reason: `超过${NOW_WINDOW_DAYS}天无互动`,
    });
    continue;
  }

  // 需要聊天文件判断
  const filename = cidToFilename(conv.cid);
  if (!filename) { skipped++; continue; }
  const filepath = path.join(CHAT_DIR, filename);
  if (!fs.existsSync(filepath)) { skipped++; continue; }

  let raw;
  try {
    raw = JSON.parse(fs.readFileSync(filepath, "utf-8"));
  } catch {
    skipped++;
    continue;
  }

  const messages = raw.messages || [];
  const realMsgs = messages.filter((m) => !isSystemMessage(m));

  if (realMsgs.length === 0) {
    results.push({
      cid: conv.cid,
      name: conv.name,
      country: conv.complianceCountryCode || "?",
      daysSinceLastContact,
      heat: "COLD",
      stage: "未知",
      lastSender: null,
      reason: "无真实消息",
    });
    continue;
  }

  // 消息按时间倒序（最新在前），取前 CHECK_MSG_COUNT 条
  const recentMsgs = realMsgs.slice(0, CHECK_MSG_COUNT);

  // 找最后一条真实消息的发送方
  const lastMsg = recentMsgs[0];
  const lastSenderIsUs = getSenderIsUs(lastMsg);
  const lastMsgText = getMsgText(lastMsg).substring(0, 150);
  const lastMsgTime = getMsgTime(lastMsg);

  // 判定阶段
  let stage = "需求探索";
  const allText = recentMsgs.map((m) => getMsgText(m).toLowerCase()).join(" ");

  if (allText.includes("payment") || allText.includes("付款") || allText.includes("deposit") || allText.includes("定金")) {
    stage = "待付款";
  } else if (allText.includes("shipping") || allText.includes("发货") || allText.includes("tracking") || allText.includes("物流") || allText.includes("提单")) {
    stage = "待发货";
  } else if (allText.includes("quotation") || allText.includes("报价") || allText.includes("price") || allText.includes("单价") || allText.includes("usd") || allText.includes("$/")) {
    stage = "报价已发";
  } else if (allText.includes("sample") || allText.includes("样品") || allText.includes("打样")) {
    stage = "样品阶段";
  } else if (allText.includes("negotiate") || allText.includes("谈判") || allText.includes("discount") || allText.includes("折扣")) {
    stage = "谈判中";
  }

