  const hasUsInRecent = recentSenders.includes("我");

  // 计算活跃度：最近 N 条消息的时间跨度
  const recentTimeSpan = recentMsgs.length >= 2
    ? (getMsgTime(recentMsgs[0]) - getMsgTime(recentMsgs[recentMsgs.length - 1])) / 86400000
    : 999;

