      heat = "SOON";
      reason = `我方最后回复${Math.round(daysSinceLastContact)}天前，客户长期未回`;
    } else {
      heat = "SOON";
      reason = "等待客户回复";
    }
  } else {
    // 客户最后发言 → 等待我方行动
    heat = "NOW";
    reason = `客户最后发言${Math.round(daysSinceLastContact)}天前，等待我方回复`;
    if (daysSinceLastContact > 7) {
      reason += " [超期]";
    }
  }

  results.push({
    cid: conv.cid,
    name: conv.name,
    country: conv.complianceCountryCode || "?",
    daysSinceLastContact,
    heat,
    stage,
    lastSender: lastSenderIsUs ? "我" : "客",
    lastMsgPreview: lastMsgText,
    lastMsgTime: new Date(lastMsgTime).toISOString().slice(0, 10),
    reason,
  });
}

// ── 按热度排序 ──────────────────────────────────────────────
results.sort((a, b) => {
  const heatOrder = { NOW: 0, SOON: 1, COLD: 2 };
  const ha = heatOrder[a.heat] ?? 9;
  const hb = heatOrder[b.heat] ?? 9;
  if (ha !== hb) return ha - hb;
  return a.daysSinceLastContact - b.daysSinceLastContact;
});

// ── 输出 ──────────────────────────────────────────────────
const summary = {
  total: results.length,
  now: results.filter((r) => r.heat === "NOW").length,
  soon: results.filter((r) => r.heat === "SOON").length,
  cold: results.filter((r) => r.heat === "COLD").length,
  skipped,
  exportedAt: new Date().toISOString(),
};

// 写 JSON
