console.log(`跳过: ${summary.skipped}人 (无聊天文件)`);
console.log("");
console.log("完整结果: data/heat_classification.json");

// 打印 NOW 列表
console.log("\n── NOW 客户列表 ──");
const nowList = results.filter((r) => r.heat === "NOW");
for (const r of nowList) {
  console.log(`${r.name.padEnd(25)} | ${r.country.padEnd(4)} | ${String(r.daysSinceLastContact).padStart(3)}天前 | ${r.stage.padEnd(8)} | ${r.lastMsgPreview.substring(0, 80)}`);
}

