      baselines[c.cid] = {
        name: c.name,
        country: c.country,
        stage: newStage,
        stage_updated: stageUpdated,
        baselines: bl,
        meta,
        _heat: c.heat,
        _daysSinceLastContact: c.daysSinceLastContact,
