const fs = require('fs');
const baselines = JSON.parse(fs.readFileSync('D:/ClaudeWorkspace/08_客户跟进/Okki/output/factor_baselines.json','utf-8'));

// S3/S8: 算一下有多少人超过最后节点
function daysSince(blDate) {
  if (!blDate) return null;
  return Math.floor((new Date('2026-05-18') - new Date(blDate)) / 86400000);
}

let s3Over30 = 0, s8Over30 = 0, s7bOver = 0;
for (const [cid, v] of Object.entries(baselines)) {
  if (v.stage === '谈判中') {
    const d = daysSince(v.baselines.S3);
    if (d && d > 31) s3Over30++;
  }
  if (v.stage === '售后') {
    const d = daysSince(v.baselines.S8);
    if (d && d > 31) s8Over30++;
  }
  // S7b: 已签收阶段超过触发天
  if (v.stage === '已签收' && v.baselines.S7b) {
    const d = daysSince(v.baselines.S7b);
    if (d && d > 8) s7bOver++;  // 样品D7+1
  }
}
console.log('S3(谈判中) > 31天: ' + s3Over30 + ' 人 → 非终止型会每天触发');
console.log('S8(售后) > 31天: ' + s8Over30 + ' 人 → 同上');
console.log('S7b > 8天: ' + s7bOver + ' 人 → 非终止型会每天触发');

// S5a: 检查待发货客户有多少人 days < interval
const RHYTHM_S5A = { sample: 3, bulk: 7 };
let s5aWaitCount = 0, s5aTotal = 0;
for (const [cid, v] of Object.entries(baselines)) {
  if (v.stage === '待发货' && v.baselines.S5a_A) {
    s5aTotal++;
    const d = daysSince(v.baselines.S5a_A);
    const interval = v.meta.customer_type === '样品单' ? 3 : 7;
    if (d && d > 0 && d < interval) s5aWaitCount++;
  }
}
console.log('S5a 待发货中处于静默期(0<d<interval): ' + s5aWaitCount + '/' + s5aTotal + ' 人');
